// Export the products array
export const products = productDefinitions;

// Helper function to enhance product with category, image, and images fields
function enhanceProduct(product) {
  const category = categories.find(cat => cat.slug === product.categorySlug);
  const productImage = product.image || product.images?.[0] || '';
  const productImages = product.images || (productImage ? [productImage] : []);
  
  return {
    ...product,
    category,
    image: productImage,
    images: productImages
  };
}

// Helper function to get product by slug
export function getProductBySlug(slug) {
  const product = products.find(product => product.slug === slug);
  return product ? enhanceProduct(product) : null;
}

// Helper function to get category by slug
export function getCategoryBySlug(slug) {
  return categories.find(category => category.slug === slug);
}

// Helper function to get subcategory by slug
export function getSubcategoryBySlug(categorySlug, subcategorySlug) {
  const category = getCategoryBySlug(categorySlug);
  if (!category || !category.subcategories) return null;
  const sub = category.subcategories.find(sub => sub.slug === subcategorySlug);
  return sub ? { ...sub, category } : null;
}

// Helper function to get products by category
export function getProductsByCategory(categorySlug) {
  return products
    .filter(product => product.categorySlug === categorySlug)
    .map(enhanceProduct);
}

// Helper function to get products by subcategory
export function getProductsBySubcategory(categorySlug, subcategorySlug) {
  let filtered;
  // If only one parameter is provided, treat it as subcategorySlug (backward compatibility)
  if (!subcategorySlug && categorySlug) {
    filtered = products.filter(product => product.subcategorySlug === categorySlug);
  } else {
    filtered = products.filter(
      product => product.categorySlug === categorySlug && 
                 product.subcategorySlug === subcategorySlug
    );
  }
  return filtered.map(enhanceProduct);
}

// New helper function to find a subcategory by its slug across all categories
export function findSubcategoryBySlug(subcategorySlug) {
  for (const category of categories) {
    if (category.subcategories) {
      const found = category.subcategories.find(sub => sub.slug === subcategorySlug);
      if (found) {
        // Attach the category to the subcategory for reference
        return { ...found, category };
      }
    }
  }
  return null;
}

// Function to get all categories
export function getAllCategories() {
  return categories;
}

// Function to get all products with proper structure
export function getAllProducts() {
  return products.map(enhanceProduct);
}